    , 
    /**
     * Destination for the relay `SendBody.to`; `None` means the coordinator.
     */
    var `to`: kotlin.String?
    , 
    /**
     * The reply to POST as `SendBody.msg_hex` (hex of the `Message` JSON), or `None`.
     */
    var `msgHex`: kotlin.String?
    , 
    /**
     * Whether this session is finished for the guardian (stop polling it).
     */
    var `done`: kotlin.Boolean
    , 
    /**
     * `"round1"` | `"round2"` | `"adjourn"` â€” for UX/logging only.
     */
    var `kind`: kotlin.String
    
){
    

    

    
    companion object
}

/**
 * @suppress
 */
public object FfiConverterTypeRelayAction: FfiConverterRustBuffer<RelayAction> {
    override fun read(buf: ByteBuffer): RelayAction {
        return RelayAction(
            FfiConverterString.read(buf),
            FfiConverterOptionalString.read(buf),
            FfiConverterOptionalString.read(buf),
            FfiConverterBoolean.read(buf),
            FfiConverterString.read(buf),
        )
    }

    override fun allocationSize(value: RelayAction) = (
            FfiConverterString.allocationSize(value.`action`) +
            FfiConverterOptionalString.allocationSize(value.`to`) +
            FfiConverterOptionalString.allocationSize(value.`msgHex`) +
            FfiConverterBoolean.allocationSize(value.`done`) +
