            FfiConverterSequenceTypeGuardianShare.write(value.`shares`, buf)
    }
}





/**
 * Errors returned by the Steward mobile SDK.
 */
sealed class StewardException: kotlin.Exception() {
    
    /**
     * JSON (de)serialization failed â€” a malformed share / package / message.
     */
    class Json(
        
        /**
         * Underlying serde_json message.
         */
        val `msg`: kotlin.String
